# build.sws — Example build script in sws
#
# Demonstrates: if/else, while, incr, command substitution,
#   pragma run-rc, $rc record, exists?

pragma run-rc on

echo "=== Build Script ==="

# Track build steps
set step 0
set errors 0

# Step 1: compile
incr step
echo "Step" $step ": compile"
run tc24r main.c -o main.s
if {eq $rc.run 0} {
    echo "  compile OK (exit" $rc.prog ")"
} else {
    echo "  compile FAILED:" $rc.msg
    incr errors
}

# Step 2: assemble
incr step
echo "Step" $step ": assemble"
run as24 main.s -o main.bin
if {eq $rc.run 0} {
    echo "  assemble OK"
} else {
    echo "  assemble FAILED:" $rc.msg
    incr errors
}

# Report
echo ""
if {eq $errors 0} {
    echo "Build succeeded in" $step "steps"
} else {
    echo "Build failed with" $errors "error(s)"
    exit 1
}
# hello.sws — Hello World in sws
#
# Demonstrates: echo, set, $var substitution, quoted strings

echo "Hello, World!"

# Variables and substitution
set name "COR24"
echo "Hello from" $name

# Integer values
set year 2026
echo "Year:" $year
# system-check.sws — System information script in sws
#
# Demonstrates: env get/set, exists?, arithmetic, while loop,
#   command substitution, fexists

echo "=== System Check ==="

# Set up environment
env set HOSTNAME cor24-dev
env set USER admin

echo "Host:" (env get HOSTNAME)
echo "User:" (env get USER)

# Check working directory
echo "CWD:" (pwd)

# Arithmetic: compute a checksum-like value
set sum 0
set i 1
while {le $i 10} {
    set sum (+ $sum (* $i $i))
    incr i
}
echo "Sum of squares 1-10:" $sum

# Variable existence checks
set config_loaded 1
if {exists? $config_loaded} {
    echo "Config: loaded"
} else {
    echo "Config: not loaded"
}

# Check for missing variable
if {exists? $missing_var} {
    echo "unexpected"
} else {
    echo "Missing var check: OK"
}

# Check filesystem (stub)
echo "Checking /bin..." (fexists /bin)

echo ""
echo "System check complete"

